function randomBetween(min, max) { return Math.random() * (max - min) + min; }

const fc = {
  double({ min = 0, max = 1 } = {}) {
    return { __arb: 'double', sample: () => randomBetween(min, max) };
  },
  asyncProperty(...args) {
    const predicate = args.pop();
    return { arbs: args, predicate };
  },
  async assert(property, { numRuns = 100 } = {}) {
    for (let i = 0; i < numRuns; i += 1) {
      const values = property.arbs.map((a) => a.sample());
      await property.predicate(...values);
    }
  },
};

export default fc;
